/// <summary>
/// Data contract for the ETG DMS Revere Integration business event.
/// Holds primary key values, collection names, and data area context.
/// </summary>
[DataContract]
internal final class ETGDMSRevereIntegrationContract extends BusinessEventsContract
{
    str PrimaryKeyCollection, PrimaryCollectionName, DataAreaId,operationType;

}

Method.Source:
[DataMember("PrimaryKeyCollection")]
public str parmPrimaryKeyCollection(str _PrimaryKeyCollection = PrimaryKeyCollection)
{
    PrimaryKeyCollection = _PrimaryKeyCollection;
    return PrimaryKeyCollection;
}

[DataMember("PrimaryCollectionName")]
public str parmPrimaryCollectionName(str _PrimaryCollectionName = PrimaryCollectionName)
{
    PrimaryCollectionName = _PrimaryCollectionName;
    return PrimaryCollectionName;
}

[DataMember("DataAreaId")]
public str parmDataAreaId(str _DataAreaId = DataAreaId)
{
    DataAreaId = _DataAreaId;
    return DataAreaId;
}

[DataMember("operationType")]
public str parmoperationType(str _operationType = operationType)
{
    operationType = _operationType;
    return operationType;
}
